class ScreenshotError(Exception):
    """Custom exception for screenshot errors."""
    pass


class ValidationError(Exception):
    """Custom exception for validation errors."""
    pass


def validate_url(url):
    """Validate and sanitize the provided URL."""
    if not url or not isinstance(url, str):
        raise ValidationError("URL is required and must be a string")

    url = url.strip()

    if len(url) > app.config['MAX_URL_LENGTH']:
        raise ValidationError(f"URL exceeds maximum length of {app.config['MAX_URL_LENGTH']}")

    parsed = urlparse(url)

    if parsed.scheme not in app.config['ALLOWED_SCHEMES']:
        raise ValidationError(f"URL scheme must be one of: {app.config['ALLOWED_SCHEMES']}")

    if not parsed.netloc:
        raise ValidationError("Invalid URL: missing hostname")

    hostname = parsed.hostname
    if hostname in app.config['BLOCKED_HOSTS']:
        raise ValidationError("Access to this host is not allowed")

    # Block private IP ranges
    try:
        import ipaddress
        try:
            ip = ipaddress.ip_address(hostname)
            if ip.is_private or ip.is_loopback or ip.is_link_local:
                raise ValidationError("Access to private/internal IPs is not allowed")
        except ValueError:
            # Not an IP address, it's a hostname - that's fine
            pass
    except ImportError:
        pass

    return url


def generate_url_hash(url):
    """Generate a consistent hash for a URL to use as cache key."""
    return hashlib.sha256(url.encode('utf-8')).hexdigest()[:16]


def get_s3_key(url_hash, size="thumbnail"):
    """Generate S3 key for the screenshot."""
    return f"screenshots/{size}/{url_hash}.png"


def check_cache(url_hash):
    """Check if a screenshot already exists in cache/S3."""
    if REDIS_AVAILABLE:
        cached = redis_client.get(f"screenshot:{url_hash}")
        if cached:
            data = json.loads(cached)
            logger.info(f"Cache hit for {url_hash}")
            return data

    # Check S3 directly
    s3_key = get_s3_key(url_hash)
    try:
        s3_client.head_object(Bucket=app.config['S3_BUCKET'], Key=s3_key)
        s3_url = get_s3_url(s3_key)
        result = {
            'url_hash': url_hash,
            's3_key': s3_key,
            's3_url': s3_url,
            'cached': True,
        }
        if REDIS_AVAILABLE:
            redis_client.setex(
                f"screenshot:{url_hash}",
                app.config['CACHE_TTL'],
                json.dumps(result)
            )
        return result
    except ClientError:
        return None


def check_rate_limit(client_ip):
    """Rate limit requests per client IP."""
    if not REDIS_AVAILABLE:
        return True

    key = f"rate_limit:{client_ip}"
    current = redis_client.get(key)

    if current is None:
        redis_client.setex(key, 60, 1)
        return True

    if int(current) >= app.config['RATE_LIMIT_PER_MINUTE']:
        return False

    redis_client.incr(key)
    return True


def get_s3_url(s3_key):
    """Generate the public S3 URL for a screenshot."""
    return f"https://{app.config['S3_BUCKET']}.s3.{app.config['S3_REGION']}.amazonaws.com/{s3_key}"


def create_chrome_driver():
    """Create and configure headless Chrome driver."""
    chrome_options = Options()
    chrome_options.add_argument('--headless')
    chrome_options.add_argument('--no-sandbox')
    chrome_options.add_argument('--disable-dev-shm-usage')
    chrome_options.add_argument('--disable-gpu')
    chrome_options.add_argument('--disable-extensions')
    chrome_options.add_argument('--disable-plugins')
    chrome_options.add_argument('--disable-images')  # Faster loading
    chrome_options.add_argument(f'--window-size={app.config["SCREENSHOT_WIDTH"]},{app.config["SCREENSHOT_HEIGHT"]}')
    chrome_options.add_argument('--hide-scrollbars')
    chrome_options.add_argument('--single-process')
    chrome_options.add_argument('--ignore-certificate-errors')
    chrome_options.add_argument('--disable-web-security')
    chrome_options.add_argument('--allow-running-insecure-content')
    chrome_options.add_argument('--user-agent=Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36')

    if app.config['CHROME_BINARY_PATH']:
        chrome_options.binary_location = app.config['CHROME_BINARY_PATH']

    service = Service(executable_path=app.config['CHROME_DRIVER_PATH'])

    driver = webdriver.Chrome(service=service, options=chrome_options)
    driver.set_page_load_timeout(app.config['SCREENSHOT_TIMEOUT'])
    driver.set_script_timeout(app.config['SCREENSHOT_TIMEOUT'])

    return driver


def take_screenshot(url):
    """Take a screenshot of the given URL using headless Chrome."""
    driver = None
    try:
        driver = create_chrome_driver()
        logger.info(f"Navigating to: {url}")

        driver.get(url)

        # Wait for page to be reasonably loaded
        WebDriverWait(driver, app.config['SCREENSHOT_TIMEOUT']).until(
            lambda d: d.execute_script('return document.readyState') == 'complete'
        )

        # Additional wait for dynamic content
        time.sleep(2)

        # Take screenshot
        screenshot_png = driver.get_screenshot_as_png()

        # Get page metadata
        title = driver.title or ''
        try:
            description = driver.execute_script(
                """
                var meta = document.querySelector('meta[name="description"]') || 
                           document.querySelector('meta[property="og:description"]');
                return meta ? meta.getAttribute('content') : '';
                """
            ) or ''
        except Exception:
            description = ''

        try:
            og_image = driver.execute_script(
                """
                var meta = document.querySelector('meta[property="og:image"]');
                return meta ? meta.getAttribute('content') : '';
                """
            ) or ''
        except Exception:
            og_image = ''

        logger.info(f"Screenshot taken successfully for: {url}")
        return screenshot_png, {
            'title': title[:500],
            'description': description[:1000],
            'og_image': og_image[:2048],
        }

    except Exception as e:
        logger.error(f"Error taking screenshot of {url}: {str(e)}")
        raise ScreenshotError(f"Failed to capture screenshot: {str(e)}")
    finally:
        if driver:
            try:
                driver.quit()
            except Exception:
                pass


def create_thumbnail(screenshot_png, width=None, height=None):
    """Create a thumbnail from the full screenshot."""
    width = width or app.config['THUMBNAIL_WIDTH']
    height = height or app.config['THUMBNAIL_HEIGHT']

    image = Image.open(io.BytesIO(screenshot_png))

    # Calculate crop dimensions to maintain aspect ratio
    target_ratio = width / height
    img_ratio = image.width / image.height

    if img_ratio > target_ratio:
        # Image is wider than target, crop width
        new_width = int(image.height * target_ratio)
        left = 0
        top = 0
        right = new_width
        bottom = image.height
    else:
        # Image is taller than target, crop height
        new_height = int(image.width / target_ratio)
        left = 0
        top = 0
        right = image.width
        bottom = new_height

    image = image.crop((left, top, right, bottom))
    image = image.resize((width, height), Image.LANCZOS)

    # Save to bytes
    buffer = io.BytesIO()
    image.save(buffer, format='PNG', optimize=True)
    buffer.seek(0)

    return buffer.getvalue()


def upload_to_s3(image_data, s3_key, content_type='image/png'):
    """Upload image data to S3."""
    try:
        s3_client.put_object(
            Bucket=app.config['S3_BUCKET'],
            Key=s3_key,
            Body=image_data,
            ContentType=content_type,
            CacheControl='public, max-age=86400',
            ACL='public-read',
        )
        logger.info(f"Uploaded to S3: {s3_key}")
        return get_s3_url(s3_key)
    except ClientError as e:
        logger.error(f"S3 upload error: {str(e)}")
        raise ScreenshotError(f"Failed to upload screenshot to S3: {str(e)}")


def ensure_s3_bucket_exists():
    """Ensure the S3 bucket exists, create if not."""
    try:
        s3_client.head_bucket(Bucket=app.config['S3_BUCKET'])
    except ClientError:
        try:
            if app.config['S3_REGION'] == 'us-east-1':
                s3_client.create_bucket(Bucket=app.config['S3_BUCKET'])
            else:
                s3_client.create_bucket(
                    Bucket=app.config['S3_BUCKET'],
                    CreateBucketConfiguration={
                        'LocationConstraint': app.config['S3_REGION']
                    }
                )
            logger.info(f"Created S3 bucket: {app.config['S3_BUCKET']}")
        except ClientError as e:
            logger.error(f"Failed to create S3 bucket: {e}")


