@app.route('/api/v1/screenshot', methods=['POST'])
def capture_screenshot():
    """
    Main endpoint to capture a screenshot and return thumbnail URL.
    
    Request body:
    {
        "url": "https://example.com",
        "width": 600,       (optional)
        "height": 400,      (optional)
        "force_refresh": false  (optional)
    }
    """
    client_ip = request.remote_addr or '0.0.0.0'

    # Rate limiting
    if not check_rate_limit(client_ip):
        return jsonify({
            'error': 'Rate limit exceeded',
            'message': f'Maximum {app.config["RATE_LIMIT_PER_MINUTE"]} requests per minute'
        }), 429

    # Parse request
    data = request.get_json(silent=True) or {}
    url = data.get('url', '').strip()
    width = data.get('width', app.config['THUMBNAIL_WIDTH'])
    height = data.get('height', app.config['THUMBNAIL_HEIGHT'])
    force_refresh = data.get('force_refresh', False)

    # Validate URL
    try:
        url = validate_url(url)
    except ValidationError as e:
        return jsonify({'error': 'Validation error', 'message': str(e)}), 400

    # Validate dimensions
    try:
        width = int(width)
        height = int(height)
        if width < 50 or width > 3840 or height < 50 or height > 2160:
            raise ValueError
    except (ValueError, TypeError):
        return jsonify({
            'error': 'Validation error',
            'message': 'Width must be 50-3840, height must be 50-2160'
        }), 400

    url_hash = generate_url_hash(url)

    # Check cache unless force refresh
    if not force_refresh:
        cached_result = check_cache(url_hash)
        if cached_result:
            cached_result['cached'] = True
            cached_result['original_url'] = url
            return jsonify(cached_result), 200

    # Take screenshot
    try:
        screenshot_png, metadata = take_screenshot(url)
    except ScreenshotError as e:
        return jsonify({
            'error': 'Screenshot failed',
            'message': str(e)
        }), 502

    # Create thumbnail
    try:
        thumbnail_data = create_thumbnail(screenshot_png, width, height)
    except Exception as e:
        logger.error(f"Thumbnail creation failed: {e}")
        return jsonify({
            'error': 'Processing error',
            'message': 'Failed to create thumbnail'
        }), 500

    # Upload full screenshot to S3
    full_s3_key = get_s3_key(url_hash, 'full')
    try:
        full_s3_url = upload_to_s3(screenshot_png, full_s3_key)
    except ScreenshotError as e:
        return jsonify({
            'error': 'Upload failed',
            'message': str(e)
        }), 500

    # Upload thumbnail to S3
    thumb_s3_key = get_s3_key(url_hash, 'thumbnail')
    try:
        thumb_s3_url = upload_to_s3(thumbnail_data, thumb_s3_key)
    except ScreenshotError as e:
        return jsonify({
            'error': 'Upload failed',
            'message': str(e)
        }), 500

    # Build response
    result = {
        'url_hash': url_hash,
        'original_url': url,
        'thumbnail_url': thumb_s3_url,
        'full_screenshot_url': full_s3_url,
        's3_key': thumb_s3_key,
        's3_url': thumb_s3_url,
        'thumbnail_width': width,
        'thumbnail_height': height,
        'metadata': metadata,
        'cached': False,
        'created_at': datetime.utcnow().isoformat(),
    }

    # Store in cache
    if REDIS_AVAILABLE:
        cache_data = {
            'url_hash': url_hash,
            's3_key': thumb_s3_key,
            's3_url': thumb_s3_url,
            'thumbnail_url': thumb_s3_url,
            'full_screenshot_url': full_s3_url,
            'metadata': metadata,
        }
        redis_client.setex(
            f"screenshot:{url_hash}",
            app.config['CACHE_TTL'],
            json.dumps(cache_data)
        )

    return jsonify(result), 201


@app.route('/api/v1/screenshot', methods=['GET'])
def get_screenshot():
    """
    Get a screenshot by URL (checks cache first).
    
    Query params:
        url: The URL to screenshot
    """
    url = request.args.get('url', '').strip()

    try:
        url = validate_url(url)
    except ValidationError as e:
        return jsonify({'error': 'Validation error', 'message': str(e)}), 400

    url_hash = generate_url_hash(url)
    cached_result = check_cache(url_hash)

    if cached_result:
        cached_result['original_url'] = url
        cached_result['cached'] = True
        return jsonify(cached_result), 200

    return jsonify({
        'error': 'Not found',
        'message': 'Screenshot not found. Use POST to create one.',
        'url_hash': url_hash,
    }), 404


@app.route('/api/v1/screenshot/<url_hash>', methods=['GET'])
def get_screenshot_by_hash(url_hash):
    """Get screenshot info by its hash."""
    cached_result = check_cache(url_hash)
    if cached_result:
        return jsonify(cached_result), 200

    return jsonify({
        'error': 'Not found',
        'message': 'Screenshot not found',
    }), 404


@app.route('/api/v1/screenshot/<url_hash>', methods=['DELETE'])
def delete_screenshot(url_hash):
    """Delete a screenshot from S3 and cache."""
    # Delete from S3
    try:
        for size in ['thumbnail', 'full']:
            s3_key = get_s3_key(url_hash, size)
            try:
                s3_client.delete_object(
                    Bucket=app.config['S3_BUCKET'],
                    Key=s3_key
                )
            except ClientError:
                pass

        # Delete from cache
        if REDIS_AVAILABLE:
            redis_client.delete(f"screenshot:{url_hash}")

        return jsonify({'message': 'Screenshot deleted', 'url_hash': url_hash}), 200
    except Exception as e:
        return jsonify({'error': 'Delete failed', 'message': str(e)}), 500


@app.route('/api/v1/screenshot/batch', methods=['POST'])
def batch_screenshot():
    """
    Take screenshots of multiple URLs.
    
    Request body:
    {
        "urls": ["https://example.com", "https://example.org"]
    }
    """
    client_ip = request.remote_addr or '0.0.0.0'

    data = request.get_json(silent=True) or {}
    urls = data.get('urls', [])

    if not isinstance(urls, list) or len(urls) == 0:
        return jsonify({'error': 'Validation error', 'message': 'urls must be a non-empty list'}), 400

    if len(urls) > 10:
        return jsonify({'error': 'Validation error', 'message': 'Maximum 10 URLs per batch'}), 400

    results = []
    for url in urls:
        try:
            url = validate_url(url)
            url_hash = generate_url_hash(url)

            # Check cache first
            cached = check_cache(url_hash)
            if cached:
                cached['original_url'] = url
                cached['cached'] = True
                cached['status'] = 'success'
                results.append(cached)
                continue

            # Check rate limit
            if not check_rate_limit(client_ip):
                results.append({
                    'original_url': url,
                    'status': 'error',
                    'error': 'Rate limit exceeded'
                })
                continue

            # Take screenshot
            screenshot_png, metadata = take_screenshot(url)
            thumbnail_data = create_thumbnail(screenshot_png)

            full_s3_key = get_s3_key(url_hash, 'full')
            full_s3_url = upload_to_s3(screenshot_png, full_s3_key)

            thumb_s3_key = get_s3_key(url_hash, 'thumbnail')
            thumb_s3_url = upload_to_s3(thumbnail_data, thumb_s3_key)

            result = {
                'url_hash': url_hash,
                'original_url': url,
                'thumbnail_url': thumb_s3_url,
                'full_screenshot_url': full_s3_url,
                'metadata': metadata,
                'cached': False,
                'status': 'success',
            }

            if REDIS_AVAILABLE:
                cache_data = {
                    'url_hash': url_hash,
                    's3_key': thumb_s3_key,
                    's3_url': thumb_s3_url,
                    'thumbnail_url': thumb_s3_url,
                    'full_screenshot_url': full_s3_url,
                    'metadata': metadata,
                }
                redis_client.setex(
                    f"screenshot:{url_hash}",
                    app.config['CACHE_TTL'],
                    json.dumps(cache_data)
                )

            results.append(result)

        except (ValidationError, ScreenshotError) as e:
            results.append({
                'original_url': url,
                'status': 'error',
                'error': str(e)
            })

    return jsonify({
        'results': results,
        'total': len(results),
        'successful': sum(1 for r in results if r.get('status') == 'success'),
    }), 200


@app.route('/api/v1/preview', methods=['GET'])
def preview_redirect():
    """
    Redirect to the thumbnail image directly.
    Useful for embedding in img tags.
    
    Query params:
        url: The URL to get preview for
    """
    url = request.args.get('url', '').strip()

    try:
        url = validate_url(url)
    except ValidationError:
        return jsonify({'error': 'Invalid URL'}), 400

    url_hash = generate_url_hash(url)
    cached = check_cache(url_hash)

    if cached and cached.get('s3_url'):
        from flask import redirect
        return redirect(cached['s3_url'], code=302)

    return jsonify({
        'error': 'Not found',
        'message': 'Screenshot not found. Use POST /api/v1/screenshot to create one.'
    }), 404


